import React from 'react';
import { BrowserRouter as Router, Route, Routes } from 'react-router-dom';
import Header from './components/Header';
import Footer from './components/Footer';
import HomePage from './pages/home';
import QuiJeSuis from './pages/qui_je_suis';
import MesServices from './pages/services';
import MesCompetences from './pages/competences';
import MesProjets from './pages/projets';
import Contacts from './pages/contact';

const App = () => {
  return (
    <Router>
      <Header />
      <Routes>
        <Route path="/" element={<HomePage />} />
        <Route path="/qui_je_suis" element={<QuiJeSuis />} />
        <Route path="/services" element={<MesServices />} />
        <Route path="/competences" element={<MesCompetences />} />
        <Route path="/projets" element={<MesProjets />} />
        <Route path="/contacts" element={<Contacts />} />
      </Routes>
      <Footer />
    </Router>
  );
};

export default App;
